  ('medical-tech-moex-20138', 'medical-tech', 'medical-tech-moex-094-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '有關抗病毒藥物Acyclovir，下列敘述何者正確？ 可以用來治療Enterovirus   可以阻斷病毒與宿主細胞之結合 分子標的為Herpesvirus之thymidine kinase  可以抑制Herpesvirus之protease', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "ddc770ac4570", "answer_pdf_sha1": "8c8cd0a5aebb", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 64, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
